@dataclass(frozen=True)
class ProblemConfig:
    num_rows: int
    num_cols: int
    mass: int

    @property
    def size_name(self) -> str:
        return f"{self.num_rows}x{self.num_cols}"


@dataclass(frozen=True)
class ReferenceDistribution:
    config: ProblemConfig
