# =============================================================================
# Margin generation
# =============================================================================

def card_like_margins(num_rows: int, num_cols: int, mass: int) -> tuple[list[int], list[int]]:
    if num_rows <= 0 or num_cols <= 0:
        raise ValueError("num_rows and num_cols must be positive")
    if mass < 0:
        raise ValueError("mass must be non-negative")

    rows = [0] * num_rows
    cols = [0] * num_cols

    # Rows: roughly balanced hand sizes.
    for i in range(mass):
        rows[i % num_rows] += 1

    # Columns: small bounded piles spread over card types in a pseudo-random order.
    remaining = mass

    for i in range(num_cols):
        if remaining == 0:
            break

        col = (i * 7 + 3) % num_cols

        if i % 6 == 0:
            cap = 0
        elif i % 6 == 1:
            cap = 1
        elif i % 6 == 2:
            cap = 2
        elif i % 6 == 3:
            cap = 3
        else:
            cap = 4

        amount = min(cap, remaining)
        cols[col] += amount
        remaining -= amount

    i = 0
    while remaining > 0:
        col = (i * 7 + 3) % num_cols
        cols[col] += 1
        remaining -= 1
        i += 1

    if sum(rows) != sum(cols):
        raise RuntimeError("Generated inconsistent margins")

    return rows, cols


# =============================================================================
# Sampling wrappers
# =============================================================================

def seed_numpy_global(seed: int) -> None:
    """
    scripts/mass_mixing.py currently uses np.random directly, not a passed
    Generator, so seeding the global NumPy RNG is the practical way to make
    trials reproducible.
    """
    np.random.seed(seed)


def generate_batch(
    row_margins: list[int],
    col_margins: list[int],
    num_samples: int,
    initialization_steps: int,
    mixing_per_sample: int,
    seed: int,
) -> list[np.ndarray]:
    if num_samples <= 0:
        raise ValueError("num_samples must be positive")
    if initialization_steps < 0:
        raise ValueError("initialization_steps must be non-negative")
    if mixing_per_sample < 0:
        raise ValueError("mixing_per_sample must be non-negative")

    seed_numpy_global(seed)

    samples: list[np.ndarray] = []

    # Important: copy samples as they are yielded. The Python generator may reuse
    # the same mutable state object internally.
    for sample in generate_with_mixing(
        num_to_generate=num_samples,
        row_constraints=row_margins,
        col_constraints=col_margins,
        initial_mixing_steps=initialization_steps,
        mixing_per_sample=mixing_per_sample,
    ):
        sample = np.asarray(sample, dtype=np.int64).copy()
        validate_matrix(sample, row_margins, col_margins)
        samples.append(sample)

    if len(samples) != num_samples:
        raise RuntimeError(f"Expected {num_samples} samples, got {len(samples)}")

    return samples


def generate_independent_initialization_batch(
    row_margins: list[int],
    col_margins: list[int],
    batch_size: int,
    initialization_steps: int,
    seed: int,
) -> list[np.ndarray]:
    if batch_size <= 0:
        raise ValueError("batch_size must be positive")
    if initialization_steps < 0:
        raise ValueError("initialization_steps must be non-negative")

    samples: list[np.ndarray] = []

    # Use different deterministic seeds for each independent initialization.
    for sample_idx in range(batch_size):
        samples.extend(
            generate_batch(
                row_margins=row_margins,
                col_margins=col_margins,
                num_samples=1,
                initialization_steps=initialization_steps,
                mixing_per_sample=0,
                seed=seed + sample_idx,
            )
        )

    if len(samples) != batch_size:
        raise RuntimeError(f"Expected {batch_size} samples, got {len(samples)}")

    return samples


# =============================================================================
# Empirical distributions and Sinkhorn
# =============================================================================

def state_key(state: np.ndarray) -> tuple[int, ...]:
    return tuple(np.asarray(state, dtype=np.int64).ravel().tolist())


def flatten_states(states: np.ndarray) -> np.ndarray:
    if states.ndim != 3:
        raise ValueError("states must have shape (num_states, rows, cols)")

    return states.reshape(states.shape[0], -1).astype(np.float64)


def empirical_support_distribution(
    samples: Iterable[np.ndarray],
) -> tuple[np.ndarray, np.ndarray]:
    counts: dict[tuple[int, ...], int] = {}
    examples: dict[tuple[int, ...], np.ndarray] = {}
    total = 0

    for sample in samples:
        key = state_key(sample)

        counts[key] = counts.get(key, 0) + 1
        if key not in examples:
            examples[key] = np.asarray(sample, dtype=np.int64).copy()

        total += 1

    if total == 0:
        raise ValueError("Cannot build empirical distribution from zero samples")

    support_states = []
    support_probs = []

    for key, count in counts.items():
        support_states.append(examples[key])
        support_probs.append(count / total)

    return np.stack(support_states, axis=0), np.array(support_probs, dtype=np.float64)


def rectangular_normalized_squared_cost(
    left_flat: np.ndarray,
    right_flat: np.ndarray,
    mass: int,
) -> np.ndarray:
    """
    Pairwise normalized squared Euclidean costs between two sets of flattened states.

        cost[i, j] = ||left[i] - right[j]||^2 / mass^2
    """
    if left_flat.ndim != 2 or right_flat.ndim != 2:
        raise ValueError("left_flat and right_flat must be 2D")
    if left_flat.shape[1] != right_flat.shape[1]:
        raise ValueError(
            f"State dimensions do not match: {left_flat.shape[1]} != {right_flat.shape[1]}"
        )
    if mass <= 0:
        raise ValueError("mass must be positive")

    left_norms = np.sum(left_flat * left_flat, axis=1)
    right_norms = np.sum(right_flat * right_flat, axis=1)

    cost = left_norms[:, None] + right_norms[None, :] - 2.0 * (left_flat @ right_flat.T)
    cost = np.maximum(cost, 0.0)

    return cost / float(mass * mass)


def sinkhorn_cost(
    a: np.ndarray,
    b: np.ndarray,
    cost: np.ndarray,
    epsilon: float = SINKHORN_EPSILON,
    max_iter: int = SINKHORN_MAX_ITER,
    tol: float = SINKHORN_TOL,
) -> float:
    """
    Entropically regularized OT cost using Sinkhorn scaling.

    This returns <P, C> for P = diag(u) K diag(v), K = exp(-C / epsilon).
    """
    if a.ndim != 1 or b.ndim != 1:
        raise ValueError("a and b must be 1D probability vectors")
    if cost.shape != (len(a), len(b)):
        raise ValueError(f"cost has shape {cost.shape}, expected {(len(a), len(b))}")
    if epsilon <= 0:
        raise ValueError("epsilon must be positive")
    if not np.isclose(a.sum(), 1.0):
        raise ValueError(f"a must sum to 1, got {a.sum()}")
    if not np.isclose(b.sum(), 1.0):
        raise ValueError(f"b must sum to 1, got {b.sum()}")

    k = np.exp(-cost / epsilon)
    k = np.maximum(k, np.finfo(np.float64).tiny)

    u = np.ones_like(a)
    v = np.ones_like(b)

    for _ in range(max_iter):
        old_u = u

        kv = k @ v
        kv = np.maximum(kv, np.finfo(np.float64).tiny)
        u = a / kv

        ktu = k.T @ u
        ktu = np.maximum(ktu, np.finfo(np.float64).tiny)
        v = b / ktu

        if np.max(np.abs(u - old_u)) < tol:
            break

    transport = (u[:, None] * k) * v[None, :]
    return float(np.sum(transport * cost))


def distribution_loss_against_reference(
    samples: Iterable[np.ndarray],
    reference: ReferenceDistribution,
) -> float:
    support_states, support_probs = empirical_support_distribution(samples)
    support_flat = flatten_states(support_states)

    cost = rectangular_normalized_squared_cost(
        support_flat,
        reference.flat_support_states,
        reference.config.mass,
    )

    return sinkhorn_cost(
        support_probs,
        reference.support_probs,
        cost,
        epsilon=SINKHORN_EPSILON,
        max_iter=SINKHORN_MAX_ITER,
        tol=SINKHORN_TOL,
    )


# =============================================================================
# Bootstrap and normalization
# =============================================================================

def bootstrap_mean_ci(
    values: np.ndarray,
    rng: np.random.Generator,
    replicates: int = BOOTSTRAP_REPLICATES,
    ci: float = BOOTSTRAP_CI,
) -> tuple[float, float, float]:
    if values.ndim != 1:
        raise ValueError("values must be 1D")
    if len(values) == 0:
        raise ValueError("Cannot bootstrap empty values")
    if replicates <= 0:
        raise ValueError("replicates must be positive")
    if not 0 < ci < 1:
        raise ValueError("ci must be between 0 and 1")

    means = np.empty(replicates, dtype=np.float64)

    for i in range(replicates):
        idxs = rng.integers(0, len(values), size=len(values))
        means[i] = values[idxs].mean()

    alpha = 1.0 - ci
    lower = float(np.quantile(means, alpha / 2.0))
    upper = float(np.quantile(means, 1.0 - alpha / 2.0))
    mean = float(values.mean())

    return mean, lower, upper


def add_within_mass_normalized_progress(
    summary: pd.DataFrame,
    step_col: str,
) -> pd.DataFrame:
    output = summary.copy()

    output["normalized_excess_loss"] = np.nan
    output["normalized_progress"] = np.nan
    output["normalized_progress_ci_low"] = np.nan
    output["normalized_progress_ci_high"] = np.nan

    for mass, idxs in output.groupby("mass").groups.items():
        group = output.loc[idxs].sort_values(step_col)

        losses = group["mean_loss"].to_numpy(dtype=np.float64)
        initial_loss = float(losses[0])
        min_loss = float(np.min(losses))
        denom = initial_loss - min_loss

        if denom <= 0:
            normalized_progress = np.ones_like(losses)
            normalized_excess = np.zeros_like(losses)
            progress_low = np.ones_like(losses)
            progress_high = np.ones_like(losses)
        else:
            normalized_excess = (losses - min_loss) / denom
            normalized_progress = 1.0 - normalized_excess

            low_loss = group["loss_ci_low"].to_numpy(dtype=np.float64)
            high_loss = group["loss_ci_high"].to_numpy(dtype=np.float64)

            # Since progress = 1 - (loss - min) / denom,
            # larger loss -> smaller progress.
            progress_low = 1.0 - (high_loss - min_loss) / denom
            progress_high = 1.0 - (low_loss - min_loss) / denom

            progress_low = np.clip(progress_low, -0.05, 1.05)
            progress_high = np.clip(progress_high, -0.05, 1.05)

        output.loc[group.index, "normalized_excess_loss"] = normalized_excess
        output.loc[group.index, "normalized_progress"] = normalized_progress
        output.loc[group.index, "normalized_progress_ci_low"] = progress_low
        output.loc[group.index, "normalized_progress_ci_high"] = progress_high

    return output


# =============================================================================
# Restartable file helpers
# =============================================================================

def write_metadata(path: Path, metadata: dict[str, object]) -> None:
    with path.open("w", encoding="utf-8") as f:
        json.dump(metadata, f, indent=2, sort_keys=True)


def completed_csv(path: Path, expected_rows: int | None = None) -> bool:
    if not path.exists():
        return False

    try:
        df = pd.read_csv(path)
    except Exception:
        return False

    if "completed" not in df.columns:
        return False
    if not bool(df["completed"].all()):
        return False
    if expected_rows is not None and len(df) != expected_rows:
        return False

    return True


def config_dir(output_dir: Path, experiment: str, config: ProblemConfig, steps: int | None = None) -> Path:
    base = output_dir / experiment / config.size_name / f"mass_{config.mass}"
    if steps is not None:
        return base / f"steps_{steps:04d}"
    return base


def result_csv_path(output_dir: Path, experiment: str, config: ProblemConfig, steps: int) -> Path:
    return config_dir(output_dir, experiment, config, steps) / "results.csv"


# =============================================================================
# Reference generation
# =============================================================================

def reference_paths(output_dir: Path, config: ProblemConfig) -> tuple[Path, Path, Path]:
    ref_dir = config_dir(output_dir, "reference", config)
    return ref_dir, ref_dir / "reserve_distribution.npz", ref_dir / "metadata.json"


def load_reference_distribution(output_dir: Path, config: ProblemConfig) -> ReferenceDistribution | None:
    ref_dir, npz_path, metadata_path = reference_paths(output_dir, config)

    if not npz_path.exists() or not metadata_path.exists():
        return None

    row_margins, col_margins = card_like_margins(config.num_rows, config.num_cols, config.mass)

    loaded = np.load(npz_path, allow_pickle=False)
    support_states = loaded["support_states"]
    support_probs = loaded["support_probs"]

    return ReferenceDistribution(
        config=config,
        row_margins=row_margins,
        col_margins=col_margins,
        support_states=support_states,
        flat_support_states=flatten_states(support_states),
        support_probs=support_probs,
    )


def build_reference_distribution(
    output_dir: Path,
    config: ProblemConfig,
    seed: int,
) -> ReferenceDistribution:
    loaded = load_reference_distribution(output_dir, config)
    if loaded is not None:
        return loaded

    ref_dir, npz_path, metadata_path = reference_paths(output_dir, config)
    ref_dir.mkdir(parents=True, exist_ok=True)

    row_margins, col_margins = card_like_margins(config.num_rows, config.num_cols, config.mass)

    metadata = {
        "experiment": "reference",
        "config": asdict(config),
        "row_margins": row_margins,
        "col_margins": col_margins,
        "num_batches": NUM_BATCHES,
        "batch_size": BATCH_SIZE,
        "total_samples": TOTAL_SAMPLES,
        "initialization_steps": REFERENCE_INITIALIZATION_STEPS,
        "mixing_per_sample": REFERENCE_MIXING_PER_SAMPLE,
        "seed": seed,
    }
    write_metadata(metadata_path, metadata)

    all_samples: list[np.ndarray] = []

    for batch_idx in tqdm(
        range(NUM_BATCHES),
        desc=f"reference {config.size_name} mass={config.mass}",
        leave=False,
    ):
        batch = generate_batch(
            row_margins=row_margins,
            col_margins=col_margins,
            num_samples=BATCH_SIZE,
            initialization_steps=REFERENCE_INITIALIZATION_STEPS,
            mixing_per_sample=REFERENCE_MIXING_PER_SAMPLE,
            seed=seed + batch_idx,
        )
        all_samples.extend(batch)

        # Save a partial support occasionally in case the run is interrupted.
        if (batch_idx + 1) % 25 == 0:
            support_states, support_probs = empirical_support_distribution(all_samples)
            np.savez_compressed(
                ref_dir / "reserve_distribution_partial.npz",
                support_states=support_states,
                support_probs=support_probs,
            )

    support_states, support_probs = empirical_support_distribution(all_samples)

    np.savez_compressed(
        npz_path,
        support_states=support_states,
        support_probs=support_probs,
    )

    return ReferenceDistribution(
        config=config,
        row_margins=row_margins,
        col_margins=col_margins,
        support_states=support_states,
        flat_support_states=flatten_states(support_states),
        support_probs=support_probs,
    )


