def run_mixing_per_sample_trial(
    reference: ReferenceDistribution,
    mixing_per_sample: int,
    output_dir: Path,
    seed: int,
) -> None:
    results_path = result_csv_path(
        output_dir,
        "mixing_per_sample",
        reference.config,
        mixing_per_sample,
    )

    if completed_csv(results_path, expected_rows=NUM_BATCHES):
        return

    trial_dir = results_path.parent
    trial_dir.mkdir(parents=True, exist_ok=True)

    metadata = {
        "experiment": "mixing_per_sample",
        "config": asdict(reference.config),
        "row_margins": reference.row_margins,
        "col_margins": reference.col_margins,
        "mixing_per_sample": mixing_per_sample,
        "initialization_steps": MIXING_TEST_INITIALIZATION_STEPS,
        "num_batches": NUM_BATCHES,
        "batch_size": BATCH_SIZE,
        "total_samples": TOTAL_SAMPLES,
        "reference_mixing_per_sample": REFERENCE_MIXING_PER_SAMPLE,
        "reference_initialization_steps": REFERENCE_INITIALIZATION_STEPS,
        "reference_support_size": int(reference.support_states.shape[0]),
        "seed": seed,
    }
    write_metadata(trial_dir / "metadata.json", metadata)

    rows: list[dict[str, object]] = []

    for batch_idx in tqdm(
        range(NUM_BATCHES),
        desc=f"mix {reference.config.size_name} mass={reference.config.mass} steps={mixing_per_sample}",
        leave=False,
    ):
        batch = generate_batch(
            row_margins=reference.row_margins,
            col_margins=reference.col_margins,
            num_samples=BATCH_SIZE,
            initialization_steps=MIXING_TEST_INITIALIZATION_STEPS,
            mixing_per_sample=mixing_per_sample,
            seed=seed + batch_idx,
        )

        loss = distribution_loss_against_reference(batch, reference)

        row = {
            "completed": True,
            "experiment": "mixing_per_sample",
            "size": reference.config.size_name,
            "num_rows": reference.config.num_rows,
            "num_cols": reference.config.num_cols,
            "mass": reference.config.mass,
            "mixing_per_sample": mixing_per_sample,
            "initialization_steps": MIXING_TEST_INITIALIZATION_STEPS,
            "batch_idx": batch_idx,
            "batch_size": BATCH_SIZE,
            "loss": loss,
            "reference_support_size": reference.support_states.shape[0],
            "seed": seed,
        }
        rows.append(row)

        pd.DataFrame(rows).to_csv(results_path, index=False)


