def write_summaries_and_plots(output_dir: Path) -> None:
    plots_dir = output_dir / "plots"
    plots_dir.mkdir(parents=True, exist_ok=True)

    mixing_raw = read_experiment_results(output_dir, "mixing_per_sample")
    initialization_raw = read_experiment_results(output_dir, "initialization")

    mixing_summary = summarize_batch_losses(mixing_raw, step_col="mixing_per_sample")
    initialization_summary = summarize_batch_losses(initialization_raw, step_col="initialization_steps")

    mixing_raw.to_csv(output_dir / "mixing_per_sample_raw.csv", index=False)
    initialization_raw.to_csv(output_dir / "initialization_raw.csv", index=False)
    mixing_summary.to_csv(output_dir / "mixing_per_sample_summary.csv", index=False)
    initialization_summary.to_csv(output_dir / "initialization_summary.csv", index=False)

    plot_raw_loss_by_mass(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=plots_dir / "mixing_raw_loss_by_mass.png",
        title=(
            "18x18 mixing-per-sample loss vs high-mixing reserve\n"
            "Raw Sinkhorn loss, one line per mass"
        ),
        x_label="Mixing steps between samples",
    )

    plot_raw_loss_by_mass(
        initialization_summary,
        step_col="initialization_steps",
        output_path=plots_dir / "initialization_raw_loss_by_mass.png",
        title=(
            "18x18 initialization loss vs high-mixing reserve\n"
            "Raw Sinkhorn loss, one line per mass"
        ),
        x_label="Initialization mixing steps",
    )

    plot_normalized_progress_by_mass(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=plots_dir / "mixing_normalized_progress_by_mass.png",
        title=(
            "18x18 mixing-per-sample normalized progress\n"
            "Hypothesis value: 324 = 18×18"
        ),
        x_label="Mixing steps between samples",
    )

    plot_normalized_progress_by_mass(
        initialization_summary,
        step_col="initialization_steps",
        output_path=plots_dir / "initialization_normalized_progress_by_mass.png",
        title=(
            "18x18 initialization normalized progress\n"
            "Hypothesis values: 648 = 2×18×18, 972 = 3×18×18"
        ),
        x_label="Initialization mixing steps",
    )


# =============================================================================
# CLI
# =============================================================================

def main() -> None:
    parser = argparse.ArgumentParser(
        description="Run large 18x18 mass-mixing experiments against high-mixing reserve distributions."
    )

    parser.add_argument(
        "--output-dir",
        type=Path,
        default=OUTPUT_DIR,
        help=f"Output directory. Default: {OUTPUT_DIR}",
    )

    parser.add_argument(
        "--plots-only",
        action="store_true",
        help="Only regenerate summaries and plots from existing results.",
    )

    args = parser.parse_args()

    args.output_dir.mkdir(parents=True, exist_ok=True)

    if not args.plots_only:
        run_all_trials(args.output_dir)

    write_summaries_and_plots(args.output_dir)

    print(f"Wrote experiment results to: {args.output_dir}")
    print(f"Wrote plots to: {args.output_dir / 'plots'}")


if __name__ == "__main__":
    main()